import {
    UserOutlined,
    SettingOutlined,
    LogoutOutlined,
    FormOutlined,
    DownloadOutlined,
    FileTextOutlined,
    AreaChartOutlined,
    MonitorOutlined,
    ImportOutlined,
    TeamOutlined,
    CheckCircleOutlined,
    BarsOutlined,
    MenuOutlined,
    HomeOutlined,
} from '@ant-design/icons'
import { useDataQuery } from '@dhis2/app-runtime'
import { Button, Layout, Menu } from 'antd'
import React, { useState } from 'react'
import classes from './App.module.css'
import './App.css'
import Home from './components/Home/Home'

const { Sider, Content } = Layout

const ME_QUERY = {
    me: {
        resource: 'me',
        params: {
            fields: ['firstName', 'surname', 'email'],
        },
    },
}

const MyApp = () => {
    const [collapsed, setCollapsed] = useState(false)
    const [openKeys, setOpenKeys] = useState(['3'])
    const { loading, error } = useDataQuery(ME_QUERY)

    if (loading || error) {
        return null
    }

    const dataCollectionItems = [
        {
            key: '3.1',
            label: <a href="/sims-web-capture/">Forms</a>,
            icon: <FormOutlined />,
        },
        {
            key: '3.2',
            label: <a href="/sims-web-aggregate-data-entry/">Spreadsheets</a>,
            icon: <FileTextOutlined />,
        },
        {
            key: '3.3',
            label: <a href="/sims-web-import-export/">Data Import &amp; Export</a>,
            icon: <DownloadOutlined />,
        },
    ]

    const adminCentreItems = [
        {
            key: '5.1',
            icon: <MonitorOutlined />,
            label: <a href="/sims-web-usage-analytics/">Usage Analytics</a>,
        },
        {
            key: '5.2',
            icon: <TeamOutlined />,
            label: <a href="/sims-web-user/">User Management</a>,
        },
        {
            key: '5.3',
            icon: <SettingOutlined />,
            label: <a href="/sims-web-settings/">System Settings</a>,
        },
        {
            key: '5.4',
            icon: <BarsOutlined />,
            label: (
                <a href="/sims-web-maintenance/#/organisationUnitSection/hierarchy">
                    Hierarchy Operations
                </a>
            ),
        },
    ]

    const onOpenChange = (keys) => {
        const rootSubmenuKeys = ['2', '5']
        const latestOpenKey = keys.find((key) => !openKeys.includes(key))

        if (rootSubmenuKeys.includes(latestOpenKey)) {
            setOpenKeys(latestOpenKey ? [latestOpenKey] : [])
        } else {
            setOpenKeys(keys)
        }
    }

    const profileMenu = (
        <Menu>
            <Menu.Item key="profile-settings" icon={<SettingOutlined />}>
                <a href="/sims-web-user-profile/#/profile">Settings</a>
            </Menu.Item>
            <Menu.Item key="account" icon={<UserOutlined />}>
                <a href="/sims-web-user-profile/#/account">Account</a>
            </Menu.Item>
            <Menu.Item key="logout" icon={<LogoutOutlined />}>
                <a href="/dhis-web-commons-security/logout.action">Logout</a>
            </Menu.Item>
        </Menu>
    )

    return (
        <Layout style={{ height: '100vh' }}>
            <Sider
                trigger={null}
                collapsible
                width="20%"
                collapsedWidth={80}
                collapsed={collapsed}
                onCollapse={(collapsedState) => setCollapsed(collapsedState)}
                breakpoint="lg"
                onBreakpoint={(broken) => setCollapsed(broken)}
                className={classes.sidebar}
                style={{
                    padding: '10px 0',
                    transition: 'width 0.2s',
                    background: '#003D8F',
                    borderRight: '1px solid #d9d9d9',
                    overflow: 'hidden',
                }}
            >
                <div
                    style={{
                        display: 'flex',
                        flexDirection: 'column',
                        background: '#003D8F',
                        height: '100%',
                    }}
                >
                    {/* Top Section */}
                    <div
                        style={{
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            gap: '10px',
                            flexShrink: 0,
                        }}
                    >
                        <div
                            className={classes.logo}
                            style={{
                                flexDirection: collapsed ? 'column-reverse' : undefined,
                            }}
                        >
                            <Button
                                type="text"
                                icon={<MenuOutlined />}
                                onClick={() => setCollapsed(!collapsed)}
                                style={{
                                    width: '16px',
                                    height: '16px',
                                    color: '#fff',
                                }}
                            />
                            <div>
                                <img
                                    src="sims-sidebar-logo.png"
                                    alt="SIMS"
                                    style={{
                                        width: collapsed ? '30px' : '40px',
                                        height: collapsed ? '30px' : '40px',
                                        objectFit: 'cover',
                                        transition: 'all 0.2s',
                                        filter: 'brightness(0) invert(1)',
                                    }}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Scrollable Menu Section */}
                    <div
                        style={{
                            overflowY: 'auto',
                            overflowX: 'hidden',
                            display: 'flex',
                            flexDirection: 'column',
                            height: '100%',
                        }}
                    >
                        <Menu
                            selectedKeys={['1']}
                            openKeys={openKeys}
                            onOpenChange={onOpenChange}
                            style={{ height: '100%' }}
                            className={classes.menu}
                            defaultSelectedKeys={['1']}
                            defaultOpenKeys={['sub1']}
                            mode="inline"
                            inlineCollapsed={collapsed}
                        >
                            <Menu.Item key="1" icon={<HomeOutlined />}>
                                <a href="/sims-web-app/">Home</a>
                            </Menu.Item>

                            <Menu.Divider />

                            <Menu.SubMenu
                                key="2"
                                icon={<CheckCircleOutlined />}
                                title="Activation"
                            >
                                <Menu.Item key="2.1" icon={<BarsOutlined />}>
                                    <a href="/sims-web-maintenance/#/list/organisationUnitSection/organisationUnit">
                                        Thematic Areas
                                    </a>
                                </Menu.Item>
                                <Menu.Item key="2.2" icon={<BarsOutlined />}>
                                    <a href="/sims-web-maintenance/#/list/organisationUnitSection/programsHierarchy">
                                        Programs
                                    </a>
                                </Menu.Item>
                                <Menu.Item key="2.3" icon={<BarsOutlined />}>
                                    <a href="/sims-web-maintenance/#/list/programSection/program">
                                        Projects
                                    </a>
                                </Menu.Item>
                                <Menu.Item key="2.4" icon={<BarsOutlined />}>
                                    <a href="/sims-web-maintenance/#/list/dataElementSection/dataElement">
                                        Data Elements
                                    </a>
                                </Menu.Item>
                                <Menu.Item key="2.5" icon={<BarsOutlined />}>
                                    <a href="/sims-web-maintenance/#/list/dataSetSection/dataSet">
                                        Data Sets
                                    </a>
                                </Menu.Item>
                            </Menu.SubMenu>

                            <Menu.Divider />

                            <Menu.SubMenu
                                key="3"
                                icon={<ImportOutlined />}
                                title="Data Collection"
                            >
                                {dataCollectionItems.map((item) => (
                                    <Menu.Item key={item.key} icon={item.icon}>
                                        {item.label}
                                    </Menu.Item>
                                ))}
                            </Menu.SubMenu>

                            <Menu.Divider />

                            <Menu.Item key="4" icon={<AreaChartOutlined />}>
                                <a href="/sims-web-dashboard/">Visualization</a>
                            </Menu.Item>

                            <Menu.Divider />

                            <Menu.SubMenu
                                key="5"
                                icon={<UserOutlined />}
                                title="Admin Centre"
                                style={{ marginTop: 'auto' }}
                            >
                                {adminCentreItems.map((item) => (
                                    <Menu.Item key={item.key} icon={item.icon}>
                                        {item.label}
                                    </Menu.Item>
                                ))}
                            </Menu.SubMenu>
                        </Menu>
                    </div>

                    {/* Profile Section */}
                    <div>{profileMenu}</div>
                </div>
            </Sider>

            <Layout
                style={{
                    padding: '0 15px 15px 15px',
                    height: '100vh',
                    overflow: 'hidden',
                }}
            >
                <Content
                    style={{
                        margin: 0,
                        display: 'flex',
                        flexDirection: 'column',
                        padding: 0,
                        height: '100%',
                        overflow: 'auto',
                    }}
                >
                    <Home />
                </Content>
            </Layout>
        </Layout>
    )
}

export default MyApp
